namespace sv_d5afa22a49494bd7a3dc36fe1960cfb2.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(
    string Description,
    DateTimeOffset Timestamp);

using sv_d5afa22a49494bd7a3dc36fe1960cfb2.Client.Services;

namespace sv_d5afa22a49494bd7a3dc36fe1960cfb2.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            "PKG-001",
            "In Transit",
            "Memphis, TN",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new("Package picked up", DateTimeOffset.UtcNow.AddDays(-3)),
                new("Arrived at sorting facility", DateTimeOffset.UtcNow.AddDays(-2)),
                new("Departed Memphis hub", DateTimeOffset.UtcNow.AddDays(-1))
            }),
        ["PKG-002"] = new ShipmentDetails(
            "PKG-002",
            "Delivered",
            "Austin, TX",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new("Package picked up", DateTimeOffset.UtcNow.AddDays(-5)),
                new("In transit", DateTimeOffset.UtcNow.AddDays(-4)),
                new("Out for delivery", DateTimeOffset.UtcNow.AddDays(-1)),
                new("Delivered - left at front door", DateTimeOffset.UtcNow.AddDays(-1).AddHours(3))
            }),
        ["PKG-003"] = new ShipmentDetails(
            "PKG-003",
            "Processing",
            "Seattle, WA",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new("Label created", DateTimeOffset.UtcNow.AddHours(-6)),
                new("Awaiting carrier pickup", DateTimeOffset.UtcNow.AddHours(-2))
            })
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");
    }
}

using System.Net.Http.Json;

namespace sv_d5afa22a49494bd7a3dc36fe1960cfb2.Client.Services;

public class HttpShipmentService : IShipmentService
{
    private readonly HttpClient _http;

    public HttpShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct))!;
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_d5afa22a49494bd7a3dc36fe1960cfb2.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>History</h3>
    <ul>
        @foreach (var update in _shipment.Updates)
        {
            <li><strong>@update.Timestamp.ToString("g")</strong> — @update.Description</li>
        }
    </ul>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync()
    {
        return LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        CancelPending();

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading this shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

